import{_ as t,o,c as a,ag as n}from"./chunks/framework.ePeAWSvT.js";const c=JSON.parse('{"title":"Versioning","description":"","frontmatter":{},"headers":[],"relativePath":"guide/versioning.md","filePath":"guide/versioning.md"}'),r={name:"guide/versioning.md"};function s(i,e,l,d,g,h){return o(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="versioning" tabindex="-1">Versioning <a class="header-anchor" href="#versioning" aria-label="Permalink to &quot;Versioning&quot;">​</a></h1><p>Data Hubs and Data Providers use a versioning system to manage configuration changes safely. There are three configuration version statuses:</p><table tabindex="0"><thead><tr><th>Status</th><th>Definition</th></tr></thead><tbody><tr><td><strong>Draft</strong></td><td>The Data Hub/Provider is a work-in-progress -- currently in the design, build, and/or testing phase. Both a Live and Draft status can be held simultaneously. When modifications are made to a Live Data Hub, a draft copy is created to design, build, and test the connections prior to publishing. Once published, the draft/modified version will supersede the current live version. You can view the version history by selecting <strong>Deploy</strong> &gt; <strong>Data Hubs</strong>, then selecting the applicable Data Hub in the left column.</td></tr><tr><td><strong>Live</strong></td><td>The Data Hub/Provider is live in the Production environment today. Live versions are read-only; a draft version must be created to modify (see note in Draft status definition).</td></tr><tr><td><strong>Previous Deploy</strong></td><td>The Data Hub/Provider was in the Production environment, but has been superseded by a newer deployed version.</td></tr></tbody></table><h2 id="view-all-versions-of-a-data-hub" tabindex="-1">View All Versions of a Data Hub <a class="header-anchor" href="#view-all-versions-of-a-data-hub" aria-label="Permalink to &quot;View All Versions of a Data Hub&quot;">​</a></h2><ol><li>Select <strong>Deploy</strong> from the main menu and ensure the <strong>Data Hubs</strong> tab is selected.</li><li>Select the appropriate <strong>Data Hub</strong> from the left column.</li><li>As needed, use the table below to determine next steps.</li></ol><table tabindex="0"><thead><tr><th>To</th><th>Do this</th></tr></thead><tbody><tr><td><strong>View Data Hub Status</strong></td><td>The <strong>status</strong> is shown in the left column of the Data Hub table.</td></tr><tr><td><strong>Add Comments</strong></td><td>Select <strong>Actions</strong> &gt; <strong>Comments</strong>. Enter text in the <strong>Comments</strong> field, then select <strong>Save</strong>.</td></tr><tr><td><strong>Deploy a Data Hub</strong></td><td>Select <strong>Actions</strong> &gt; <strong>Deploy</strong>.</td></tr><tr><td><strong>Compare with Live</strong></td><td>Select <strong>Actions</strong> &gt; <strong>Compare with Live</strong>. In the <strong>Compare Configurations</strong> window, view the side-by-side code for any changes and to ensure accuracy. When finished, select <strong>Close</strong>.</td></tr><tr><td><strong>Compare with Previous</strong></td><td>Select <strong>Actions</strong> &gt; <strong>Compare with Previous</strong>. In the <strong>Compare Configurations</strong> window, view the side-by-side code for any changes and to ensure accuracy. When finished, select <strong>Close</strong>.</td></tr><tr><td><strong>View Code</strong></td><td>Select <strong>Actions</strong> &gt; <strong>View Code</strong>. View the code to ensure accuracy; when finished, select <strong>Close</strong>.</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>When comparing versions within the Compare Configurations window, you can toggle the following icons to assist in comparing the versions: <strong>View Inline</strong>, <strong>Previous Change</strong>, <strong>Next Change</strong>, and <strong>Ignore Trailing/Leading Whitespace</strong>.</p></div><h2 id="create-a-new-draft-version-of-a-live-data-hub" tabindex="-1">Create a New Draft Version of a Live Data Hub <a class="header-anchor" href="#create-a-new-draft-version-of-a-live-data-hub" aria-label="Permalink to &quot;Create a New Draft Version of a Live Data Hub&quot;">​</a></h2><p>Once a Data Hub has been deployed, it is Live. If you need to make changes, you need to create a new Draft version of the Data Hub, edit that version, and deploy it to supersede the current Live version. This ensures the current version of the Data Hub is still running and enables you to make changes and run testing prior to deploying an updated version. You can have several Draft versions of the same Data Hub.</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>You could also revert to a Previously Deployed version of the Data Hub while making edits to the most recent Live version; however, it is advised to modify a Draft copy of the latest version.</p></div><ol><li>Select <strong>Build</strong> &gt; <strong>Data Hubs</strong> from the main menu.</li><li>Select the appropriate <strong>Data Hub</strong>.</li><li>Select <strong>Actions</strong> &gt; <strong>+ New Draft</strong>.</li></ol><div class="info custom-block"><p class="custom-block-title">Note</p><p>You can have only one (1) Draft and one (1) Live version of the same Data Hub; therefore, you will only see this option when there is only a Live and Previously Deployed version of this Data Hub. See the <a href="#">Versioning</a> section for more information.</p></div><ol start="4"><li>A new Draft version will appear, where you can modify and save any changes.</li></ol><h2 id="delete-a-data-hub" tabindex="-1">Delete a Data Hub <a class="header-anchor" href="#delete-a-data-hub" aria-label="Permalink to &quot;Delete a Data Hub&quot;">​</a></h2><p>Users are able to delete a Data Hub in any status (e.g. Draft, Live). This will remove all components of the Data Hub; however, your <a href="./build-data-models.html">Data Models</a> will still be valid, so you are able to use those to build a new Data Hub as needed.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Once a hub has been deleted, all integrations inside that Hub will immediately be turned off in production.</p></div><ol><li>Select <strong>Build</strong> &gt; <strong>Data Hubs</strong> from the main menu.</li><li>Select the appropriate <strong>Data Hub</strong>.</li><li>Select <strong>Actions</strong> &gt; <strong>Delete Data Hub</strong>.</li><li>Select <strong>OK</strong> to confirm the deletion.</li></ol><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./deploy.html">Deployments</a> — Deploy Data Hub configurations</li><li><a href="./build-datahubs.html">Building Data Hubs</a> — Create and configure Data Hubs</li><li><a href="./datahub-code-view.html">Code View</a> — View and edit the underlying Data Hub configuration</li><li><a href="./monitor-dashboard.html">Monitor Dashboard</a> — Track deployment health after going live</li></ul>',19)])])}const b=t(r,[["render",s]]);export{c as __pageData,b as default};
